def init_board():
    board = np.zeros((BOARD_SIZE, BOARD_SIZE), dtype=int)
    for i in range(3, 5):
        for j in range(1, BOARD_SIZE, 2):
            if (i + j) % 2 == 0:
                board[i, j] = -1
        for j in range(0, BOARD_SIZE, 2):
            if (i + j) % 2 == 1:
                board[i, j] = 1
    return board

