def print_board(board):
    mapping = {-1: 'X', 0: '.', 1: 'O'}
    for row in board:
        print(' '.join(mapping[cell] for cell in row))

# Function to check if a move is valid
def is_valid_move(board, start_row, start_col, end_row, end_col):
    # Check if the piece is present at the start position
    if board[start_row, start_col] == 0:
        return False
    # Check if the move goes to an empty cell
    if board[end_row, end_col] != 0:
        return False
    # Check if it's a valid non-capture move
    if abs(start_row - end_row) == 1 and abs(start_col - end_col) == 1:
        return True
    # Check if it's a valid capture move
    if abs(start_row - end_row) == 2 and abs(start_col - end_col) == 2:
        intermediate_cell = board[(start_row + end_row) // 2, (start_col + end_col) // 2]
